import socket
import threading
import json
import time
import math

class GameServer:
    def __init__(self, host='127.0.0.1', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((host, port))
        self.server_socket.listen()
        self.clients = []
        self.player_positions = {}

    def start(self):
        print("Server started, waiting for clients...")
        while True:
            client_socket, addr = self.server_socket.accept()
            print(f"Client connected: {addr}")
            self.clients.append(client_socket)
            threading.Thread(target=self.handle_client, args=(client_socket,)).start()

    def handle_client(self, client_socket):
        while True:
            try:
                data = client_socket.recv(1024)
                if not data:
                    break
                player_data = json.loads(data.decode())
                self.update_player_position(player_data)
                self.broadcast_game_state()
            except Exception as e:
                print(f"Error: {e}")
                break
        self.remove_client(client_socket)

    def update_player_position(self, player_data):
        player_id = player_data['id']
        position = player_data['position']
        self.player_positions[player_id] = position

    def broadcast_game_state(self):
        game_state = json.dumps(self.player_positions)
        for client in self.clients:
            try:
                client.send(game_state.encode())
            except Exception as e:
                print(f"Error sending to client: {e}")

    def remove_client(self, client_socket):
        self.clients.remove(client_socket)
        client_socket.close()

if __name__ == "__main__":
    server = GameServer()
    server.start()